import{_ as t,o as e,c as n,a0 as i}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"阿尔塔纳 (Altana)","description":"","frontmatter":{"type":"concept","title":"阿尔塔纳 (Altana)","tags":["gintama","concept","worldbuilding"],"related":["gintama","utsuro","tendoshuu","gintoki-sakata"],"sources":["anime/39486.md"],"created":"2026-07-10T00:00:00.000Z","updated":"2026-07-10T00:00:00.000Z","date":"2026-07-10T00:00:00.000Z"},"headers":[],"relativePath":"concepts/阿尔塔纳-altana.md","filePath":"concepts/阿尔塔纳-altana.md"}'),l={name:"concepts/阿尔塔纳-altana.md"};function o(s,a,r,h,u,d){return e(),n("div",null,[...a[0]||(a[0]=[i('<h1 id="阿尔塔纳-altana" tabindex="-1">阿尔塔纳 (Altana) <a class="header-anchor" href="#阿尔塔纳-altana" aria-label="Permalink to &quot;阿尔塔纳 (Altana)&quot;">​</a></h1><p>阿尔塔纳（Altana）是《银魂》世界观中的核心设定元素，指代地球的龙脉或能量流。</p><h2 id="在最终章中的作用" tabindex="-1">在最终章中的作用 <a class="header-anchor" href="#在最终章中的作用" aria-label="Permalink to &quot;在最终章中的作用&quot;">​</a></h2><p>在《<a href="/entities/gintama-银魂.html">5-anime--5-39486--1xtfkzd</a>》中，<a href="/entities/坂田银时-gintoki-sakata.html">gintoki-sakata</a>通过勘测地球的龙脉（Altana）来追踪<a href="/entities/虚-utsuro.html">utsuro</a>的踪迹。Altana成为剧情驱动的关键机制，连接了银时的行动与虚的回归。<a href="/entities/天道众-tendoshuu.html">tendoshuu</a>残党对永生的追求也与Altana密切相关。</p><h2 id="关联" tabindex="-1">关联 <a class="header-anchor" href="#关联" aria-label="Permalink to &quot;关联&quot;">​</a></h2><ul><li>作品：<a href="/entities/gintama-银魂.html">gintama</a></li><li>相关人物：<a href="/entities/坂田银时-gintoki-sakata.html">gintoki-sakata</a>、<a href="/entities/虚-utsuro.html">utsuro</a></li><li>相关组织：<a href="/entities/天道众-tendoshuu.html">tendoshuu</a></li></ul>',6)])])}const _=t(l,[["render",o]]);export{m as __pageData,_ as default};
